CREATE TABLE store_metadata (singleton INTEGER PRIMARY KEY, store_id TEXT NOT NULL, schema_id TEXT NOT NULL, schema_version INTEGER NOT NULL, protocol_id TEXT NOT NULL, protocol_version INTEGER NOT NULL, initialized_at TEXT NOT NULL, initialization_operation_id TEXT NOT NULL) STRICT;
CREATE TABLE store_authority_binding (singleton INTEGER PRIMARY KEY, store_id TEXT NOT NULL, source_kind TEXT NOT NULL, source_locator TEXT NOT NULL, authority_mode TEXT NOT NULL, bound_at TEXT NOT NULL, binding_operation_id TEXT NOT NULL) STRICT;
CREATE TABLE namespaces (namespace_id TEXT PRIMARY KEY, namespace_key TEXT NOT NULL UNIQUE, lifecycle TEXT NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE view_families (view_id TEXT PRIMARY KEY, home_namespace_id TEXT NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE view_policy_revisions (view_policy_revision_id TEXT PRIMARY KEY, view_id TEXT NOT NULL, revision_number INTEGER NOT NULL, audience_ceiling TEXT NOT NULL, lifecycle TEXT NOT NULL, authority_claim_json TEXT NOT NULL, object_kinds_json TEXT NOT NULL, store_operation_receipts_visible INTEGER NOT NULL, predecessor_revision_id TEXT, activation_fence INTEGER, created_at TEXT NOT NULL, limits_json TEXT NOT NULL, superseded_fence INTEGER, retirement_fence INTEGER) STRICT;
CREATE TABLE view_policy_namespace_grants (view_policy_revision_id TEXT NOT NULL, namespace_id TEXT NOT NULL, PRIMARY KEY(view_policy_revision_id, namespace_id)) STRICT, WITHOUT ROWID;
CREATE TABLE store_fence (singleton INTEGER PRIMARY KEY, operation_fence INTEGER NOT NULL) STRICT;
CREATE TABLE store_operation_receipts (operation_id TEXT PRIMARY KEY, operation_kind TEXT NOT NULL, store_id TEXT NOT NULL, request_digest TEXT NOT NULL, outcome TEXT NOT NULL, result_json TEXT NOT NULL, result_digest TEXT NOT NULL, authority_claim_json TEXT NOT NULL, settled_at TEXT NOT NULL, failure_class TEXT, retry_disposition TEXT NOT NULL, operation_fence INTEGER NOT NULL, owner_id TEXT, owner_kind TEXT, owner_home_namespace_id TEXT, view_policy_revision_id TEXT, expected_revision INTEGER, observed_revision INTEGER, committed_revision INTEGER, event_id TEXT) STRICT;
CREATE TABLE owners (owner_id TEXT PRIMARY KEY, owner_kind TEXT NOT NULL, home_namespace_id TEXT NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE owner_family_bindings (family_id TEXT PRIMARY KEY, owner_id TEXT NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE owner_versions (version_id TEXT PRIMARY KEY, owner_id TEXT NOT NULL, family_id TEXT NOT NULL, content_json TEXT NOT NULL, content_digest TEXT NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE owner_revisions (revision_id TEXT PRIMARY KEY, owner_id TEXT NOT NULL, revision_number INTEGER NOT NULL, normalized_json TEXT NOT NULL, representation_id TEXT NOT NULL, representation_version INTEGER NOT NULL, operation_id TEXT NOT NULL, committed_at TEXT NOT NULL) STRICT;
CREATE TABLE owner_revision_selections (revision_id TEXT NOT NULL, family_id TEXT NOT NULL, version_id TEXT NOT NULL, PRIMARY KEY(revision_id,family_id)) STRICT, WITHOUT ROWID;
CREATE TABLE owner_current (owner_id TEXT PRIMARY KEY, revision_id TEXT NOT NULL, revision_number INTEGER NOT NULL, projection_json TEXT NOT NULL, updated_at TEXT NOT NULL) STRICT;
CREATE TABLE owner_events (event_id TEXT PRIMARY KEY, owner_id TEXT NOT NULL, owner_kind TEXT NOT NULL, owner_revision_id TEXT NOT NULL, owner_revision INTEGER NOT NULL, namespace_id TEXT NOT NULL, event_type TEXT NOT NULL, event_schema_version INTEGER NOT NULL, operation_id TEXT NOT NULL, causation TEXT, correlation TEXT, commit_sequence INTEGER NOT NULL, committed_at TEXT NOT NULL, visibility_ceiling TEXT NOT NULL, payload_json TEXT NOT NULL, payload_digest TEXT NOT NULL) STRICT;
CREATE TABLE owner_outbox (outbox_id TEXT PRIMARY KEY, operation_id TEXT NOT NULL, owner_id TEXT NOT NULL, outbox_kind TEXT NOT NULL, payload_json TEXT NOT NULL, payload_digest TEXT NOT NULL, commit_sequence INTEGER NOT NULL, created_at TEXT NOT NULL) STRICT;
CREATE TABLE event_retention (singleton INTEGER PRIMARY KEY, retained_after_sequence INTEGER NOT NULL) STRICT;
CREATE TABLE consumer_checkpoints (view_id TEXT NOT NULL, consumer_id TEXT NOT NULL, view_policy_revision_id TEXT NOT NULL, checkpoint_revision INTEGER NOT NULL, event_cursor TEXT NOT NULL, event_sequence INTEGER NOT NULL, snapshot_fence INTEGER NOT NULL, pending_event_ids_json TEXT NOT NULL, freshness TEXT NOT NULL, predecessor_policy_revision_id TEXT, updated_at TEXT NOT NULL, PRIMARY KEY(view_id,consumer_id)) STRICT, WITHOUT ROWID;
CREATE TABLE schema_migrations (migration_id TEXT PRIMARY KEY, schema_id TEXT NOT NULL, from_version INTEGER NOT NULL, to_version INTEGER NOT NULL, schema_asset_digest TEXT NOT NULL, migration_manifest_digest TEXT NOT NULL, operation_id TEXT NOT NULL, applied_at TEXT NOT NULL) STRICT;
CREATE TRIGGER store_metadata_immutable_update BEFORE UPDATE ON store_metadata BEGIN SELECT RAISE(ABORT, 'store metadata is immutable'); END;
CREATE TRIGGER store_operation_receipts_immutable_update BEFORE UPDATE ON store_operation_receipts BEGIN SELECT RAISE(ABORT, 'store operation receipts are immutable'); END;
CREATE TRIGGER store_operation_receipts_immutable_delete BEFORE DELETE ON store_operation_receipts BEGIN SELECT RAISE(ABORT, 'store operation receipts are immutable'); END;
CREATE TRIGGER owners_identity_immutable BEFORE UPDATE OF owner_id,owner_kind,home_namespace_id ON owners BEGIN SELECT RAISE(ABORT, 'owner identity is immutable'); END;

